proof fn phi_1_sub_distribute_commuted(a: int, b: int, c: int)
    ensures
        c * a - c * b == (a - b) * c,
{
    sub_distribute(a, b, c);
    assert(a * c == c * a) by(nonlinear_arith);
    assert(b * c == c * b) by(nonlinear_arith);
}

proof fn phi_2_sub_distribute_zero_c(a: int, b: int)
    ensures
        a * 0 - b * 0 == 0,
{
    sub_distribute(a, b, 0);
}

proof fn phi_3_sub_distribute_self(a: int, c: int)
    ensures
        a * c - a * c == 0,
{
    sub_distribute(a, a, c);
}

proof fn phi_4_sub_distribute_negative(a: int, b: int, c: int)
    requires
        a < b,
        c > 0,
    ensures
        a * c - b * c < 0,
{
    sub_distribute(a, b, c);
    assert((a - b) * c < 0) by(nonlinear_arith)
        requires a < b, c > 0;
}

proof fn phi_5_sub_distribute_factor_extraction(n: int, c: int)
    ensures
        (n + 1) * c - n * c == c,
{
    sub_distribute(n + 1, n, c);
}
